CREATE TABLE IF NOT EXISTS devlog_timeline (id INT, "content" VARCHAR(4500) NOT NULL, attachments_count INT NOT NULL, "comments" INT NOT NULL, reposts INT NOT NULL, likes INT NOT NULL, "views" INT NOT NULL, request INT, CONSTRAINT pk_devlog_timeline PRIMARY KEY (id, request), CONSTRAINT fk_devlog_timeline_id__id FOREIGN KEY (id) REFERENCES devlogs(id) ON DELETE RESTRICT ON UPDATE RESTRICT, CONSTRAINT fk_devlog_timeline_request__id FOREIGN KEY (request) REFERENCES requests(id) ON DELETE RESTRICT ON UPDATE RESTRICT);